svg.script:

(function() {
  var phrases = ["buscando prácticas", "Java, SQL, Android", "Mejorando en WEB", "Python en progreso", "Quiero crecer en equipo real", "Adaptable y con ganas de aprender", "Disponible para prácticas"];
  var textEl = document.getElementById('typing');
  var cursorEl = document.getElementById('cursor');
  var phraseIdx = 0;
  var charIdx = 0;
  var isDeleting = false;
  var currentText = '';

  function typeEffect() {
    var fullPhrase = phrases[phraseIdx];

    if (!isDeleting) {
      currentText = fullPhrase.substring(0, charIdx + 1);
      charIdx++;

      if (charIdx === fullPhrase.length) {
        isDeleting = true;
        setTimeout(typeEffect, 1800);
        return;
      }
    } else {
      currentText = fullPhrase.substring(0, charIdx - 1);
      charIdx--;

      if (charIdx === 0) {
        isDeleting = false;
        phraseIdx = (phraseIdx + 1) % phrases.length;
        setTimeout(typeEffect, 70);
        return;
      }
    }

    textEl.textContent = currentText;
    cursorEl.setAttribute('x', 148 + textEl.getComputedTextLength());

    var delay = isDeleting ? 35 : 70;
    setTimeout(typeEffect, delay);
  }

  setTimeout(typeEffect, 300);
})();
